import pika
import subprocess
import json
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class JobConsumer:
    def __init__(self, host='localhost', queue_name='job_queue'):
        self.host = host
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        self.channel.basic_qos(prefetch_count=1)
        
    def process_message(self, ch, method, properties, body):
        try:
            logger.info(f"Received message: {body}")
            
            message = json.loads(body)
            command = message.get('command', '')
            
            if not command:
                command = body.decode('utf-8')
            
            logger.info(f"Executing command: {command}")
            
            result = subprocess.run(
                command,
                shell=True,
                capture_output=True,
                text=True,
                timeout=300
            )
            
            if result.returncode == 0:
                logger.info(f"Command executed successfully: {result.stdout}")
            else:
                logger.error(f"Command failed with error: {result.stderr}")
            
            ch.basic_ack(delivery_tag=method.delivery_tag)
            
        except json.JSONDecodeError:
            try:
                command = body.decode('utf-8')
                logger.info(f"Executing raw command: {command}")
                
                result = subprocess.run(
                    command,
                    shell=True,
                    capture_output=True,
                    text=True,
                    timeout=300
                )
                
                if result.returncode == 0:
                    logger.info(f"Command executed successfully: {result.stdout}")
                else:
                    logger.error(f"Command failed with error: {result.stderr}")
                
                ch.basic_ack(delivery_tag=method.delivery_tag)
                
            except Exception as e:
                logger.error(f"Error processing raw message: {e}")
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
                
        except subprocess.TimeoutExpired:
            logger.error("Command execution timeout")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
            
        except Exception as e:
            logger.error(f"Error processing message: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    
    def start_consuming(self):
        self.connect()
        logger.info(f"Waiting for messages on queue: {self.queue_name}")
        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self.process_message
        )
        self.channel.start_consuming()
    
    def stop_consuming(self):
        if self.channel:
            self.channel.stop_consuming()
        if self.connection:
            self.connection.close()


if __name__ == '__main__':
    consumer = JobConsumer(host='localhost', queue_name='job_queue')
    try:
        consumer.start_consuming()
    except KeyboardInterrupt:
        logger.info("Stopping consumer...")
        consumer.stop_consuming()